INSERT INTO t_p80207328_code_school_online.exam_questions
  (course_id, position, question, options, correct) VALUES
('ai-prompting', 1, 'Что такое промпт?', 'Название нейросети|||Текстовый запрос к ИИ|||Ошибка в программе|||Тип VPN', 1),
('ai-prompting', 2, 'Почему подробный промпт лучше короткого?', 'Он быстрее обрабатывается|||Чем яснее запрос, тем точнее ответ ИИ|||Так требует ChatGPT|||Короткие запросы запрещены', 1),
('ai-prompting', 3, 'Что даёт назначение роли («Ты опытный маркетолог»)?', 'Ускоряет ответ|||ИИ отвечает как специалист, качество растёт|||Отключает ошибки|||Меняет язык ответа', 1),
('ai-prompting', 4, 'Что такое контекст в промпте?', 'Длина ответа|||Детали: кто ты, для кого и зачем результат|||Название модели|||Формат файла', 1),
('ai-prompting', 5, 'Техника few-shot — это когда...', 'Задаёшь один короткий вопрос|||Даёшь ИИ 1-3 примера нужного результата|||Просишь короткий ответ|||Отключаешь контекст', 1),
('ai-prompting', 6, 'Как получить ответ в виде таблицы?', 'Это невозможно|||Прямо попросить: «Формат — таблица»|||Только через код|||Нужен отдельный сервис', 1),
('ai-prompting', 7, 'Какая фраза включает пошаговое рассуждение?', '«Ответь быстро»|||«Думай шаг за шагом»|||«Будь краток»|||«Используй роль»', 1),
('ai-prompting', 8, 'Что делать, если первый ответ ИИ не идеален?', 'Начать новый чат|||Уточнять и дорабатывать в диалоге|||Считать это финалом|||Сменить нейросеть', 1),
('ai-prompting', 9, 'Что такое «галлюцинации» ИИ?', 'Красивые картинки|||Когда ИИ выдумывает недостоверные факты|||Ошибка сети|||Режим VPN', 1),
('ai-prompting', 10, 'Какая нейросеть сильна в работе с длинными текстами?', 'Midjourney|||Claude|||DALL-E|||Ни одна', 1),
('ai-prompting', 11, 'Что важно указать при генерации изображения?', 'Только цвет|||Объект, сцену, стиль, освещение|||Размер файла|||Язык интерфейса', 1),
('ai-prompting', 12, 'Главная формула хорошего промпта:', 'Только вопрос|||Задача + контекст + формат + ограничения|||Роль + эмодзи|||Длинный текст без структуры', 1);